spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    // Positions
    var shapesY = H / 2 - 35;
    var c1x = W / 2 - 55, c2x = W / 2 - 35, c3x = W / 2 - 15;
    var s1x = W / 2 + 15, s2x = W / 2 + 35;
    var radius = 7;
    var sqSize = 14;

    // Stages:
    // 0 - 2.5s: Stage 1 (show shapes)
    // 2.5s - 5.5s: Stage 2 (Part-to-Part highlight: Circles to Squares = 3:2)
    // 5.5s - 8.5s: Stage 3 (Part-to-Whole highlight: Circles to Total = 3:5)
    // 8.5s - 12s: Stage 4 (Summary)

    var stage = 1;
    if (progress >= 0.21 && progress < 0.46) stage = 2;
    else if (progress >= 0.46 && progress < 0.71) stage = 3;
    else if (progress >= 0.71) stage = 4;

    // Draw Circles (Red)
    var circleColor = (stage === 3 || stage === 4 || stage === 1) ? '#EF4444' : 'rgba(239, 68, 68, 0.4)';
    if (stage === 2) circleColor = '#EF4444'; // Bright in part-to-part

    ctx.fillStyle = circleColor;
    ctx.beginPath(); ctx.arc(c1x, shapesY, radius, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(c2x, shapesY, radius, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(c3x, shapesY, radius, 0, Math.PI * 2); ctx.fill();

    // Draw Squares (Blue)
    var squareColor = (stage === 2 || stage === 4 || stage === 1) ? '#3B82F6' : 'rgba(59, 130, 246, 0.2)';
    ctx.fillStyle = squareColor;
    ctx.fillRect(s1x - sqSize/2, shapesY - sqSize/2, sqSize, sqSize);
    ctx.fillRect(s2x - sqSize/2, shapesY - sqSize/2, sqSize, sqSize);

    // Stage borders/highlights
    if (stage === 2) {
      // Separate groups with vertical bar
      ctx.beginPath();
      ctx.moveTo(W / 2, shapesY - 20);
      ctx.lineTo(W / 2, shapesY + 20);
      ctx.strokeStyle = '#4B5563';
      ctx.lineWidth = 1.5;
      ctx.stroke();
    } else if (stage === 3) {
      // Draw thin box enclosing all 5 shapes to highlight the whole
      ctx.strokeStyle = '#8B5CF6';
      ctx.lineWidth = 1.5;
      ctx.strokeRect(c1x - 15, shapesY - 18, (s2x - c1x) + 30, 36);
    }

    // Text labels
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('A Collection of Shapes', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('3 Red Circles and 2 Blue Squares (5 shapes total)', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#3B82F6';
      ctx.fillText('Part-to-Part Ratio', W / 2, H - 45);
      ctx.font = 'bold 13px -apple-system, sans-serif';
      ctx.fillStyle = '#EF4444';
      ctx.fillText('Circles : Squares = 3 : 2', W / 2, H - 25);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Compares circles directly to squares.', W / 2, H - 9);
    } else if (stage === 3) {
      ctx.fillStyle = '#8B5CF6';
      ctx.fillText('Part-to-Whole Ratio', W / 2, H - 45);
      ctx.font = 'bold 13px -apple-system, sans-serif';
      ctx.fillStyle = '#A78BFA';
      ctx.fillText('Circles : Total Shapes = 3 : 5', W / 2, H - 25);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Compares circles to the entire set.', W / 2, H - 9);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Ratio Formats', W / 2, H - 45);
      ctx.font = 'bold 11px -apple-system, sans-serif';
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('Part-to-Part: 3 to 2  |  3:2  |  3/2', W / 2, H - 25);
      ctx.fillText('Part-to-Whole: 3 to 5  |  3:5  |  3/5', W / 2, H - 9);
    }
  }
};
